// Stock Trading Maximum Profit — Regret-Based Greedy (O(n))
//
// Problem: n days, prices a[0..n-1], per-sale transaction fee C.
//          Hold at most one share at a time. Maximize total profit.
//
// Algorithm (greedy with regret / "virtual buy" trick):
//
//   Track min_buy = minimum effective buy cost seen so far.
//
//   For each day with price p:
//     1. Update min_buy = min(min_buy, p)   [candidate fresh buy]
//     2. If p - min_buy > C:               [profitable to sell today]
//          profit += p - min_buy - C
//          min_buy = p - C                  [regret update]
//
// Why the regret update (min_buy = p - C)?
//   Suppose we "settle" a trade at price p and reset min_buy to p - C.
//   If a future price p' > p comes along, we gain:
//       (p' - min_buy - C) = (p' - (p-C) - C) = p' - p
//   This is exactly the gain from extending the original hold through day p'
//   instead of selling at p — paying the fee only once total.
//   The algorithm never actually commits to selling until it can't extend.
//
// Equivalently, this implements:
//   "Greedily take every upward move, but only net of the fee."
//
// Proof of optimality:
//   The structure of any optimal solution can be transformed to match this
//   greedy's decisions without losing profit (exchange argument). All net
//   positive sub-sequences that exceed C are captured; none below C are taken.
//
// Complexity: O(n) time, O(1) space.

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    long long C;
    cin >> n >> C;

    long long profit = 0;
    long long min_buy = LLONG_MAX;

    for (int i = 0; i < n; i++) {
        long long p;
        cin >> p;

        // Update cheapest buy candidate
        if (p < min_buy) min_buy = p;

        // Sell today if profitable after fee
        if (p - min_buy > C) {
            profit += p - min_buy - C;
            // Regret update: set virtual buy cost so future extension is free
            min_buy = p - C;
        }
    }

    cout << profit << "\n";
    return 0;
}
