from functools import lru_cache
import random, subprocess, os

def brute_force(prices, C):
    n = len(prices)
    memo = {}
    def go(day, holding, buy_price):
        if day == n: return 0
        key = (day, holding, buy_price)
        if key in memo: return memo[key]
        p = prices[day]
        best = go(day+1, holding, buy_price)  # skip
        if not holding:
            best = max(best, go(day+1, True, p) - p)  # buy
        else:
            best = max(best, p - C + go(day+1, False, -1))  # sell
        memo[key] = best
        return best
    return go(0, False, -1)

def solve_cpp(prices, C):
    inp = f'{len(prices)} {C}\n{\" \".join(map(str, prices))}\n'
    r = subprocess.run(['/tmp/isolated_workspace_1091/solution'], input=inp, capture_output=True, text=True)
