errors = 0
for trial in range(3000):
    n = random.randint(1, 10)
    prices = [random.randint(1, 50) for _ in range(n)]
    C = random.randint(0, 20)
    expected = brute_force(prices, C)
    got = solve_cpp(prices, C)
    if expected != got:
        errors += 1
        print(f'FAIL #{trial}: prices={prices} C={C} expected={expected} got={got}')
        if errors >= 5: break

if errors == 0:
    print('All 3000 stress tests passed ✓')
else:
    print(f'{errors} failures found')
"
"}

